floatingNav.css:
.mt-floating-nav {
  position: fixed; top: 0; left: 0; right: 0; z-index: 10000;
  display: flex; align-items: center; justify-content: space-between;
  padding: 8px 16px; height: 48px;
  background: rgba(13,13,15,0.92);
  backdrop-filter: blur(12px); -webkit-backdrop-filter: blur(12px);
  border-bottom: 1px solid #2a2a35;
  font-family: Inter, -apple-system, sans-serif; font-size: 13px;
}
.mt-floating-nav a, .mt-floating-nav button {
  text-decoration: none; border: none; cursor: pointer;
  padding: 5px 10px; border-radius: 6px; font-size: 13px;
  transition: background 0.2s, color 0.2s;
}
.mt-floating-nav .mt-nav-left { display: flex; align-items: center; gap: 6px; }
.mt-floating-nav .mt-nav-right { display: flex; align-items: center; gap: 6px; }
.mt-floating-nav .mt-nav-back,
.mt-floating-nav .mt-nav-home {
  background: transparent; color: #aaa;
}
.mt-floating-nav .mt-nav-back:hover,
.mt-floating-nav .mt-nav-home:hover { background: #1a1a1f; color: #e8e8e8; }
.mt-floating-nav .mt-nav-title {
  color: #f0a500; font-family: Syne, sans-serif; font-weight: 700;
  font-size: 14px; margin-left: 4px;
}
.mt-floating-nav .mt-nav-bmc {
  background: rgba(240,165,0,0.15); color: #f0a500;
}
.mt-floating-nav .mt-nav-bmc:hover { background: rgba(240,165,0,0.3); }
.mt-floating-nav .mt-nav-feedback {
  background: rgba(240,165,0,0.1); color: #f0a500;
}
.mt-floating-nav .mt-nav-feedback:hover { background: rgba(240,165,0,0.25); }
@media (max-width: 480px) {
  .mt-floating-nav { padding: 6px 10px; font-size: 12px; }
  .mt-floating-nav a, .mt-floating-nav button { padding: 4px 7px; font-size: 12px; }
  .mt-floating-nav .mt-nav-title { font-size: 12px; }
}
